import React, { useState, useEffect } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { Container, Row, Col, Card, Button, Spinner, ListGroup, Badge } from 'react-bootstrap';
import { 
  Shop, Calendar, People, Clock, Ban, BoxArrowRight, 
  ChevronRight
} from 'react-bootstrap-icons';
import { useAuth } from '../../contexts/AuthContext';
import { adminApi } from '../../services/api';

function AdminDashboard() {
  const navigate = useNavigate();
  const { user, logout } = useAuth();
  const [stats, setStats] = useState({
    appointments: 0,
    pending: 0,
    confirmed: 0,
    completed: 0,
  });
  const [recentAppointments, setRecentAppointments] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    try {
      const appointments = await adminApi.getAppointments(user.token);

      setStats({
        appointments: appointments.length,
        pending: appointments.filter(a => a.estado === 'pendiente').length,
        confirmed: appointments.filter(a => a.estado === 'confirmada').length,
        completed: appointments.filter(a => a.estado === 'completada').length,
      });

      setRecentAppointments(appointments.slice(0, 5));
    } catch (err) {
      console.error('Error loading dashboard:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = () => {
    logout();
    navigate('/admin/login');
  };

  const menuItems = [
    { path: '/admin/appointments', icon: Calendar, label: 'Citas', color: 'primary' },
    { path: '/admin/services', icon: Shop, label: 'Servicios', color: 'success' },
    { path: '/admin/employees', icon: People, label: 'Empleados', color: 'info' },
    { path: '/admin/schedules', icon: Clock, label: 'Horarios', color: 'warning' },
    { path: '/admin/blockages', icon: Ban, label: 'Bloqueos', color: 'danger' },
  ];

  const getStatusBadge = (estado) => {
    const variants = {
      pendiente: 'warning',
      confirmada: 'success',
      cancelada: 'danger',
      completada: 'primary',
      no_show: 'secondary',
    };
    return <Badge bg={variants[estado] || 'secondary'}>{estado}</Badge>;
  };

  if (loading) {
    return (
      <Container className="py-5 text-center">
        <Spinner animation="border" />
      </Container>
    );
  }

  return (
    <Container className="py-4">
      <div className="d-flex justify-content-between align-items-center mb-4">
        <div>
          <h2 className="fw-bold mb-0">Panel de Administración</h2>
          <small className="text-muted">Bienvenido, {user?.email}</small>
        </div>
        <Button variant="outline-danger" onClick={handleLogout}>
          <BoxArrowRight className="me-2" /> Cerrar sesión
        </Button>
      </div>

      {/* Stats */}
      <Row className="mb-4">
        <Col md={3}>
          <Card className="text-center">
            <Card.Body>
              <h3 className="fw-bold text-primary">{stats.appointments}</h3>
              <small className="text-muted">Total citas</small>
            </Card.Body>
          </Card>
        </Col>
        <Col md={3}>
          <Card className="text-center">
            <Card.Body>
              <h3 className="fw-bold text-warning">{stats.pending}</h3>
              <small className="text-muted">Pendientes</small>
            </Card.Body>
          </Card>
        </Col>
        <Col md={3}>
          <Card className="text-center">
            <Card.Body>
              <h3 className="fw-bold text-success">{stats.confirmed}</h3>
              <small className="text-muted">Confirmadas</small>
            </Card.Body>
          </Card>
        </Col>
        <Col md={3}>
          <Card className="text-center">
            <Card.Body>
              <h3 className="fw-bold text-info">{stats.completed}</h3>
              <small className="text-muted">Completadas</small>
            </Card.Body>
          </Card>
        </Col>
      </Row>

      <Row>
        {/* Menu */}
        <Col lg={4} className="mb-4">
          <Card>
            <Card.Body>
              <h5 className="fw-bold mb-3">Gestión</h5>
              <ListGroup variant="flush">
                {menuItems.map((item) => (
                  <ListGroup.Item
                    key={item.path}
                    action
                    as={Link}
                    to={item.path}
                    className="d-flex justify-content-between align-items-center"
                  >
                    <div>
                      <item.icon className={`me-2 text-${item.color}`} />
                      {item.label}
                    </div>
                    <ChevronRight />
                  </ListGroup.Item>
                ))}
              </ListGroup>
            </Card.Body>
          </Card>
        </Col>

        {/* Recent Appointments */}
        <Col lg={8}>
          <Card>
            <Card.Body>
              <div className="d-flex justify-content-between align-items-center mb-3">
                <h5 className="fw-bold mb-0">Citas recientes</h5>
                <Button variant="outline-primary" size="sm" as={Link} to="/admin/appointments">
                  Ver todas
                </Button>
              </div>

              {recentAppointments.length === 0 ? (
                <p className="text-muted text-center py-4">No hay citas registradas</p>
              ) : (
                <ListGroup variant="flush">
                  {recentAppointments.map((apt) => (
                    <ListGroup.Item key={apt.id} className="px-0">
                      <div className="d-flex justify-content-between align-items-center">
                        <div>
                          <strong>{apt.nombre_cliente}</strong>
                          <div className="text-muted small">
                            {new Date(apt.fecha).toLocaleDateString()} {apt.hora_inicio?.substring(0, 5)}
                          </div>
                        </div>
                        <div className="text-end">
                          {getStatusBadge(apt.estado)}
                          <div className="text-muted small">
                            {parseFloat(apt.precio_total).toFixed(2)}€
                          </div>
                        </div>
                      </div>
                    </ListGroup.Item>
                  ))}
                </ListGroup>
              )}
            </Card.Body>
          </Card>
        </Col>
      </Row>
    </Container>
  );
}

export default AdminDashboard;
